from flask import Flask, request, jsonify
import jwt
from functools import wraps

app = Flask(__name__)

# Configuration for different signing algorithms
JWT_CONFIG = {
    'internal': {'algorithm': 'HS256', 'secret': 'your-internal-secret'},
    'public_api': {'algorithm': 'RS256', 'public_key': '-----BEGIN PUBLIC KEY-----\nMIIBIjANBgkqhkiG9w0BAQEFAAOCAQ8AMIIBCgKCAQEA...\n-----END PUBLIC KEY-----'}
}

def jwt_required(algorithm):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            token = request.headers.get('Authorization')
            if not token:
                return jsonify({'message': 'Token is missing!'}), 401

            try:
                if algorithm == 'HS256':
                    decoded = jwt.decode(token, JWT_CONFIG['internal']['secret'], algorithms=[JWT_CONFIG['internal']['algorithm']])
                elif algorithm == 'RS256':
                    decoded = jwt.decode(token, JWT_CONFIG['public_api']['public_key'], algorithms=[JWT_CONFIG['public_api']['algorithm']])
                else:
                    return jsonify({'message': 'Unsupported signing algorithm!'}), 401
            except jwt.ExpiredSignatureError:
                return jsonify({'message': 'Token has expired!'}), 401
            except jwt.InvalidTokenError:
                return jsonify({'message': 'Invalid token!'}), 401

            request.jwt_payload = decoded
            return f(*args, **kwargs)
        return decorated_function
    return decorator

@app.route('/internal')
@jwt_required('HS256')
def internal_service():
    return jsonify({'message': 'This is an internal service.', 'payload': request.jwt_payload})

